changeSet.sql:
create materialized view if not exists sor.check_units as with actual_content as ( select history.content_id from sor.content_history history where end_dt = to_date('30000101', 'YYYYMMDD') ), resources as ( select resources.id check_unit_id, content_id, value check_unit_value, dsc check_unit_type from sor.content_resources resources join sor.resource_type types on resources.resource_type_id = types.id ), actual_content_types as ( select actual_content.content_id, coalesce(blocktype, 'url') blocktype from actual_content join sor.content_info content_info on actual_content.content_id=content_info.content_id) select resources.check_unit_id, actual_content_types.content_id, resources.check_unit_type, resources.check_unit_value from actual_content_types join resources on actual_content_types.content_id = resources.content_id and actual_content_types.blocktype = resources.check_unit_type;
alter materialized view sor.check_units owner to as_user;
create index if not exists check_unit_id_idx on sor.check_units (check_unit_id);
